const items = $input.all().map(i => i.json);
if (!items.length || !items[0].event_type) return [{json: {skip: true}}];

const lines = items.map(e => 
  `• ${e.target_workflow}\n  Event: ${e.event_type}\n  Error: ${e.error_message}\n  Zeit: ${new Date(e.created_at).toLocaleString('de-DE', {timeZone: 'Europe/Berlin'})}`
);

return [{json: {
  message: `🔴 FLOW MONITOR ALERT\n\n${items.length} Error(s) in letzten 15 Min:\n\n${lines.join('\n\n')}`
}}];

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');

return [{json: {
  document_base64: base64,
  mime_type: 'application/pdf',
  prompt: 'Extrahiere: company, address, external_ref. Antworte NUR mit JSON.',
  step_key: 'smoke_test:' + timestamp
}}];

const result = $input.first().json;
const success = result.success === true;
const text = result.text || '';
const model = result.model_used || 'unknown';
const attempts = result.total_attempts || '?';
const chain = (result.fallback_chain || []).join(' > ');
const ts = new Date().toLocaleString('de-DE', {timeZone: 'Europe/Berlin'});

// Response bereinigen: Newlines und Sonderzeichen entfernen
const safeText = text.substring(0, 120).replace(/[\n\r]/g, ' ').replace(/"/g, "'");

if (success && text) {
  return [{json: {
    success: true,
    message: `SMOKE TEST OK (${ts})\nModel: ${model} (Attempt ${attempts}/3)\nChain: ${chain}\nResponse: ${safeText}`
  }}];
} else {
  return [{json: {
    success: false,
    message: `SMOKE TEST FAILED (${ts})\nModel: ${model}\nSuccess: ${success}\nText empty: ${!text}\nError: ${result.log_error || 'unknown'}`
  }}];
}

const apiKey = $input.first().json.value;
const BASE = 'https://n8n.srv1045913.hstgr.cloud/api/v1';
const cutoff = new Date(Date.now() - 24*60*60*1000).toISOString();

// Fetch executions in batches
let allExecs = [];
let cursor = null;
for (let i = 0; i < 2; i++) {
  const url = cursor 
    ? `${BASE}/executions?limit=250&cursor=${cursor}` 
    : `${BASE}/executions?limit=250`;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: { 'X-N8N-API-KEY': apiKey },
      json: true
    });
    allExecs.push(...(resp.data || []));
    cursor = resp.nextCursor;
    if (!cursor) break;
  } catch(e) {
    return [{json: {error: true, message: `API Error: ${e.message}`}}];
  }
}

// Filter to 24h
const recent = allExecs.filter(e => e.stoppedAt && e.stoppedAt >= cutoff);

// Group by workflow name
const byWorkflow = {};
for (const ex of recent) {
  const name = ex.workflowData?.name || ex.workflowId || 'Unknown';
  if (!byWorkflow[name]) byWorkflow[name] = {success: 0, error: 0, total: 0};
  byWorkflow[name].total++;
  if (ex.status === 'success') byWorkflow[name].success++;
  if (ex.status === 'error') byWorkflow[name].error++;
}

// Skip self
delete byWorkflow['MX_07_Flow_Monitor'];

// Sort: errors first, then by name
const sorted = Object.entries(byWorkflow).sort((a,b) => {
  if (b[1].error !== a[1].error) return b[1].error - a[1].error;
  return a[0].localeCompare(b[0]);
});

return [{json: {
  workflows: sorted.map(([name, s]) => ({name, ...s})),
  total_executions: recent.length,
  total_errors: sorted.reduce((sum, [,s]) => sum + s.error, 0),
  error: false
}}];

const data = $input.first().json;

if (data.error) {
  return [{json: {message: '\ud83d\udcca *24h FLOW REPORT*\n\n\u26a0\ufe0f ' + data.message + '\n\nAPI Key ggf. abgelaufen \u2192 company_settings updaten'}}];
}

const flows = data.workflows || [];
const date = new Date().toLocaleDateString('de-DE', {timeZone: 'Europe/Berlin'});

const lines = flows.map(f => {
  let emoji = '\u2705';
  if (f.error > 0) emoji = '\ud83d\udd34';
  else if (f.total === 0) emoji = '\ud83d\udca4';
  return `${emoji} ${f.name}: ${f.success}/${f.total}`;
});

let message = '\ud83d\udcca *24h FLOW REPORT* (' + date + ')\n\n';

if (lines.length === 0) {
  message += '\ud83d\udca4 Keine Flow-Aktivit\u00e4t in 24h\n';
} else {
  message += lines.join('\n') + '\n';
}

message += '\nExecutions: ' + data.total_executions + ' | Errors: ' + data.total_errors;

return [{json: {message}}];

